func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get keyword query parameter
	query := r.URL.Query()
	keywords := query["keyword"]

	// Default empty keyword if not provided
	keyword := ""
	if len(keywords) > 0 {
		keyword = keywords[0]
	}

	// Escape HTML to prevent XSS
	escapedKeyword := strings.ReplaceAll(keyword, "<", "&lt;")
	escapedKeyword = strings.ReplaceAll(escapedKeyword, ">", "&gt;")

	// Write HTML response
	fmt.Fprintf(w, `<!DOCTYPE html>
<html>
<head>
	<title>Search Results</title>
</head>
<body>
	<h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	http.ListenAndServe(":8080", nil)
}

